I cannot directly render a 3D model or generate an image file (like a .obj, .fbx, or .png) within this chat interface. However, I can provide you with the **complete code** to generate a 3D house using **Three.js** (a popular JavaScript library for 3D graphics).

You can run this code immediately in your browser to see a rendered 3D house.

### Option 1: Run in Browser (Instant Visualization)
Copy the code below, save it as an `.html` file (e.g., `house.html`), and open it in any web browser.

```html
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>3D House Model</title>
    <style>
        body { margin: 0; overflow: hidden; background-color: #87CEEB; }
        canvas { display: block; }
        #info {
            position: absolute;
            top: 10px;
            width: 100%;
            text-align: center;
            color: white;
            font-family: Arial, sans-serif;
            font-weight: bold;
            text-shadow: 1px 1px 2px black;
            pointer-events: none;
        }
    </style>
</head>
<body>
    <div id="info">3D House Model (Click & Drag to Rotate)</div>

    <!-- Import Three.js from CDN -->
    <script type="importmap">
        {
            "imports": {
                "three": "https://unpkg.com/three@0.160.0/build/three.module.js",
                "three/addons/": "https://unpkg.com/three@0.160.0/examples/jsm/"
            }
        }
    </script>

    <script type="module">
        import * as THREE from 'three';
        import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

        // 1. Scene Setup
        const scene = new THREE.Scene();
        scene.background = new THREE.Color(0x87CEEB); // Sky blue
        scene.fog = new THREE.Fog(0x87CEEB, 20, 100);

        const camera = new THREE.PerspectiveCamera(60, window.innerWidth / window.innerHeight, 0.1, 1000);
        camera.position.set(15, 10, 20);

        const renderer = new THREE.WebGLRenderer({ antialias: true });
        renderer.setSize(window.innerWidth, window.innerHeight);
        renderer.shadowMap.enabled = true;
        document.body.appendChild(renderer.domElement);

        // 2. Lighting
        const ambientLight = new THREE.AmbientLight(0xffffff, 0.6);
        scene.add(ambientLight);

        const dirLight = new THREE.DirectionalLight(0xffffff, 1);
        dirLight.position.set(10, 20, 10);
        dirLight.castShadow = true;
        dirLight.shadow.mapSize.width = 2048;
        dirLight.shadow.mapSize.height = 2048;
        scene.add(dirLight);

        // 3. Build the House
        const houseGroup = new THREE.Group();

        // Materials
        const wallMaterial = new THREE.MeshStandardMaterial({ color: 0xE0E0E0 }); // White walls
        const roofMaterial = new THREE.MeshStandardMaterial({ color: 0x8B4513 }); // Brown roof
        const windowMaterial = new THREE.MeshStandardMaterial({ color: 0x87CEEB, transparent: true, opacity: 0.6 });
        const doorMaterial = new THREE.MeshStandardMaterial({ color: 0x5C4033 });

        // Base Geometry
        const baseGeo = new THREE.BoxGeometry(10, 4, 10);
        const baseMesh = new THREE.Mesh(baseGeo, wallMaterial);
        baseMesh.position.y = 2;
        baseMesh.castShadow = true;
        baseMesh.receiveShadow = true;
        houseGroup.add(baseMesh);

        // Roof Geometry (Pyramid)
        const roofGeo = new THREE.ConeGeometry(8, 4, 4);
        const roofMesh = new THREE.Mesh(roofGeo, roofMaterial);
        roofMesh.position.y = 6;
        roofMesh.rotation.y = Math.PI / 4;
        roofMesh.castShadow = true;
        houseGroup.add(roofMesh);

        // Windows
        const windowGeo = new THREE.BoxGeometry(2, 1.5, 0.2);

        // Front Windows
        const win1 = new THREE.Mesh(windowGeo, windowMaterial);
        win1.position.set(-2, 3, 5.1);
        houseGroup.add(win1);

        const win2 = new THREE.Mesh(windowGeo, windowMaterial);
        win2.position.set(2, 3, 5.1);
        houseGroup.add(win2);

        // Back Windows
        const win3 = new THREE.Mesh(windowGeo, windowMaterial);
        win3.position.set(-2, 3, -5.1);
        houseGroup.add(win3);

        const win4 = new THREE.Mesh(windowGeo, windowMaterial);
        win4.position.set(2, 3, -5.1);
        houseGroup.add(win4);

        // Door
        const doorGeo = new THREE.BoxGeometry(2, 3, 0.2);
        const door = new THREE.Mesh(doorGeo, doorMaterial);
        door.position.set(0, 1.5, 5.1);
        houseGroup.add(door);

        // Chimney
        const chimneyGeo = new THREE.BoxGeometry(1, 3, 1);
        const chimney = new THREE.Mesh(chimneyGeo, new THREE.MeshStandardMaterial({color: 0x555555}));
        chimney.position.set(3, 8, 0);
        houseGroup.add(chimney);

        scene.add(houseGroup);

        // 4. Ground
        const groundGeo = new THREE.PlaneGeometry(200, 200);
        const groundMat = new THREE.MeshStandardMaterial({ color: 0x228B22 }); // Forest Green
        const ground = new THREE.Mesh(groundGeo, groundMat);
        ground.rotation.x = -Math.PI / 2;
        ground.receiveShadow = true;
        scene.add(ground);

        // 5. Controls
        const controls = new OrbitControls(camera, renderer.domElement);
        controls.enableDamping = true;
        controls.maxPolarAngle = Math.PI / 2 - 0.1; // Prevent going under ground

        // 6. Animation Loop
        function animate() {
            requestAnimationFrame(animate);
            controls.update();
            renderer.render(scene, camera);
        }

        // Handle Resize
        window.addEventListener('resize', () => {
            camera.aspect = window.innerWidth / window.innerHeight;
            camera.updateProjectionMatrix();
            renderer.setSize(window.innerWidth, window.innerHeight);
        });

        animate();
    </script>
</body>
</html>
```

### Option 2: Python (Using Blender via Python)
If you have Python installed and want to generate a file that can be opened in Blender, you can use the `blender` API.

**Prerequisites:**
1. Install Blender.
2. Install the `blender` python package: `pip install blender`

**Code:**
```python
import bpy
import math

# Clear existing objects
bpy.ops.object.select_all(action='SELECT')
bpy.ops.object.delete(use_global=False)

# Create a simple house using primitives
# 1. Walls
bpy.ops.mesh.primitive_cube_add(size=2, location=(0, 0, 2))
walls = bpy.context.active_object
walls.name = "Walls"
walls.scale = (5, 1, 1) # Make it wider
bpy.ops.object.transform_apply(location=True, rotation=True, scale=True)

# 2. Roof
bpy.ops.mesh.primitive_cube_add(size=2, location=(0, 0, 4))
roof = bpy.context.active_object
roof.name = "Roof"
roof.scale = (4, 1, 1)
roof.rotation_euler = (math.radians(45), 0, 0)
bpy.ops.object.transform_apply(location=True, rotation=True, scale=True)

# 3. Door
